const NL = String.fromCharCode(10);
const items = $input.all();
const filtered = items.filter(function(item) {
  const url = item.json.screenshot_url;
  return url && typeof url === 'string' && url.indexOf('http') === 0;
});
const limited = filtered.slice(0, 10);
return limited.map(function(item) {
  return { json: item.json };
});

const NL = String.fromCharCode(10);
const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const title = item.json.title || 'Unknown Script';
  const author = item.json.author || 'Unknown Author';
  const description = item.json.description || '';
  const script_url = item.json.script_url || '';
  const screenshot_url = item.json.screenshot_url || '';

  const systemLines = [
    'You are a senior quant trader with 15+ years experience.',
    'Analyze this TradingView indicator screenshot and description.',
    'Respond in EXACTLY this JSON format (no markdown, no code blocks):',
    '{"strategy_logic":"2-3 sentences describing what this does","performance_estimate":"How it would perform on NVDA, SPY, TSLA over 6 months","overall_score":1-10,"recommendation":"One line for Quantum pipeline e.g. High priority - strong volume profile"}',
    'Return ONLY valid JSON.'
  ];
  const systemContent = systemLines.join(NL);

  const userText = 'Script Title: ' + title + NL + 'Author: ' + author + NL + 'Description: ' + description;

  const body = {
    model: 'grok-2-vision-latest',
    messages: [
      {
        role: 'system',
        content: systemContent
      },
      {
        role: 'user',
        content: [
          {
            type: 'image_url',
            image_url: { url: screenshot_url }
          },
          {
            type: 'text',
            text: userText
          }
        ]
      }
    ],
    temperature: 0.2
  };

  results.push({
    json: {
      api_body: JSON.stringify(body),
      title: title,
      author: author,
      script_url: script_url,
      screenshot_url: screenshot_url,
      description: description
    }
  });
}

return results;

const NL = String.fromCharCode(10);
const items = $input.all();
const parsed = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let analysis = {};
  try {
    const content = item.json.choices[0].message.content;
    const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
    analysis = JSON.parse(cleaned);
  } catch (e) {
    analysis = {
      strategy_logic: 'Parse error',
      performance_estimate: 'N/A',
      overall_score: 0,
      recommendation: 'Could not parse response'
    };
  }

  parsed.push({
    json: {
      title: item.json.title || '',
      author: item.json.author || '',
      script_url: item.json.script_url || '',
      screenshot_url: item.json.screenshot_url || '',
      description: item.json.description || '',
      strategy_logic: analysis.strategy_logic || '',
      performance_estimate: analysis.performance_estimate || '',
      overall_score: analysis.overall_score || 0,
      recommendation: analysis.recommendation || ''
    }
  });
}

parsed.sort(function(a, b) {
  return (b.json.overall_score || 0) - (a.json.overall_score || 0);
});

return parsed.map(function(item, idx) {
  item.json.rank = idx + 1;
  return item;
});

const NL = String.fromCharCode(10);
const items = $input.all();
const top5 = items.slice(0, 5);
const count = top5.length;

const lines = [];
lines.push('<b>Vision Discovery \u2014 Top ' + count + ' new scripts analyzed</b>');
lines.push('');

for (let i = 0; i < top5.length; i++) {
  const item = top5[i];
  const rank = item.json.rank || (i + 1);
  const title = item.json.title || 'Untitled';
  const author = item.json.author || 'Unknown';
  const score = item.json.overall_score || 0;
  const strategy = item.json.strategy_logic || '';
  const rec = item.json.recommendation || '';

  lines.push(rank + '. <b>' + title + '</b> - ' + author + ' \u2192 Score ' + score + '/10');
  lines.push('   Summary: ' + strategy);
  lines.push('   Rec: ' + rec);
  lines.push('');
}

const message = lines.join(NL);
return [{ json: { message: message } }];
